package email

import (
    "encoding/json"
    "net/http"
    "github.com/gorilla/mux"
)

type Handler struct {{
    service *Service
}}

func NewHandler(service *Service) *Handler {{
    return &Handler{{service: service}}
}}

func (h *Handler) GetAll(w http.ResponseWriter, r *http.Request) {{
    items, err := h.service.GetAll(r.Context())
    if err != nil {{
        http.Error(w, err.Error(), http.StatusInternalServerError)
        return
    }}
    json.NewEncoder(w).Encode(items)
}}

func (h *Handler) GetByID(w http.ResponseWriter, r *http.Request) {{
    vars := mux.Vars(r)
    id := vars["id"]

    item, err := h.service.GetByID(r.Context(), id)
    if err != nil {{
        http.Error(w, err.Error(), http.StatusNotFound)
        return
    }}
    json.NewEncoder(w).Encode(item)
}}

import {{ Injectable }} from '@nestjs/common';
import {{ EmailService }} from './models/email.model';
import {{ EmailServiceRepository }} from './repositories/email.repository';

@Injectable()
export class EmailServiceService {{
  constructor(
    private readonly repository: EmailServiceRepository,
  ) {{}}

  async findAll(): Promise<EmailService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<EmailService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<EmailService>): Promise<EmailService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<EmailService>): Promise<EmailService> {{
    return this.repository.update(id, data);
  }}
}}
